// ═══════════════════════════════════════════════════════
// NEURO-CHEMISTRY (Dopamine, Cortisol, Oxytocin)
// ═══════════════════════════════════════════════════════
const CHEM = {
  dopamine: 0.5, 
  cortisol: 0.2, 
  oxytocin: 0.2, // Social bond/Safety (0-1)
};

function updateChemistry() {
  // 1. Dopamine: Joy and reward boost learning
  const rewardSignal = (state.joy + state.anticipation) / 200;
  CHEM.dopamine = CHEM.dopamine * 0.9 + rewardSignal * 0.1;

  // 2. Oxytocin: Generated by Trust and social safety
  // High trust creates a "shield"
  const socialSignal = (state.trust + state.joy) / 200;
  CHEM.oxytocin = CHEM.oxytocin * 0.9 + socialSignal * 0.1;

  // 3. Cortisol: Generated by Fear/Anger, but BLOCKED by Oxytocin
  // Biologically, oxytocin suppresses the amygdala (stress alarm)
  const rawStress = (state.fear + state.anger + (CAREGIVER.stress * 100)) / 300;
  const shield = CHEM.oxytocin * 0.6; // Oxytocin blocks up to 60% of stress
  const stressSignal = Math.max(0, rawStress - shield);
  
  CHEM.cortisol = CHEM.cortisol * 0.95 + stressSignal * 0.05;

  // 4. The Protest Signal
  if (state.sadness > 60 || state.fear > 60) {
    CAREGIVER.stress = Math.min(1, CAREGIVER.stress + 0.05);
    if (Math.random() < 0.3) {
        applyEffects({trust: 10, joy: 5}, 'kindness', 'protest heard', true);
    }
  }

  applyChemicalEffects();
}

function applyChemicalEffects() {
  if (CHEM.cortisol > 0.6) {
    TEMP.effortControl = Math.max(0.1, TEMP.effortControl - 0.001);
  }
}